import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { HTMLAttributes } from 'react';
import type { AllStatuses, ColorTypes } from '../../types/status';
export type IconSize = 'small' | 'medium' | 'large';
export interface IconProps extends HTMLAttributes<HTMLButtonElement> {
    /** Размер иконки */
    size?: IconSize;
    /**
     * Цвет иконки и цвет фона
     * @deprecated
     */
    type?: AllStatuses;
    /** Указывает какого типа должна быть кнопка. Если указать type, то contained включится по умолчанию */
    contained?: boolean;
    /** Тип значка */
    iconName: Icons;
    /** Пользовательский класс*/
    className?: string;
    /** Цвет иконки и цвет фона */
    color?: ColorTypes;
    dataTestId?: string;
}
